output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?senator ?senatorLabel ?county ?countyLabel WHERE {
  ?senator wdt:P39 wd:Q12277129 .
  ?senator wdt:P102 wd:Q550159 .
  ?senator wdt:P131 ?county .
  OPTIONAL {
    ?senator rdfs:label ?senatorLabel
    FILTER(LANG(?senatorLabel) = "en")
  }
  OPTIONAL {
    ?county rdfs:label ?countyLabel
    FILTER(LANG(?countyLabel) = "en")
  }
}

